import React from 'react';
import { Link as RouterLink } from 'react-router-dom';
import { Container, Paper, Typography, Button, Box } from '@mui/material';

function Agriculture() {
  return (
    <Container maxWidth="md" sx={{ mt: 6, mb: 6 }}>
      <Paper elevation={2} sx={{ p: 4, borderRadius: 2 }}>
        <Typography variant="h4" component="h1" gutterBottom fontWeight={700}>
          Farming advisor
        </Typography>
        <Typography variant="body1" color="text.secondary" paragraph>
          This space is for personalized farming advice through the same humanoid, conversational
          experience as interview coaching. Hook your crop data, regional guidance, or agronomy APIs
          here when you are ready.
        </Typography>
        <Box sx={{ mt: 3 }}>
          <Button variant="outlined" component={RouterLink} to="/" sx={{ mr: 2 }}>
            Back to home
          </Button>
          <Button variant="contained" component={RouterLink} to="/interview">
            Try the avatar (interview)
          </Button>
        </Box>
      </Paper>
    </Container>
  );
}

export default Agriculture;
